import * as fs from 'fs';
import * as path from 'path';
import {
  APP_NAME,
  APP_VERSION,
  BUILD_ENV,
  BUILD_PATH_APPEND,
  FINISH_ARGS,
  FLATPAK_APP_ID,
  FLATPAK_RUNTIME,
  FLATPAK_RUNTIME_VERSION,
  FLATPAK_SDK,
  SDK_EXTENSIONS,
} from './build_config';

interface FlatpakBuildOptions {
  'append-path': string;
  env: Record<string, string>;
}

interface FlatpakModule {
  name: string;
  buildsystem: 'simple' | 'cmake' | 'meson' | 'autotools';
  'build-commands': string[];
  sources: FlatpakSource[];
  'build-options'?: FlatpakBuildOptions;
}

interface FlatpakSource {
  type: 'archive' | 'git' | 'file' | 'dir' | 'script' | 'shell';
  url?: string;
  sha256?: string;
  tag?: string;
  commit?: string;
  path?: string;
  dest?: string;
  commands?: string[];
}

interface FlatpakManifest {
  'app-id': string;
  runtime: string;
  'runtime-version': string;
  sdk: string;
  'sdk-extensions': string[];
  command: string;
  'finish-args': string[];
  'build-options': FlatpakBuildOptions;
  modules: FlatpakModule[];
}

function buildPromptNotesModule(): FlatpakModule {
  return {
    name: 'promptnotes',
    buildsystem: 'simple',
    'build-commands': [
      // Install Node dependencies
      'npm ci --offline',
      // Build Svelte frontend
      'npm run build',
      // Build Tauri app (Rust + bundle)
      'cargo tauri build --bundles none',
      // Install binary
      'install -Dm755 src-tauri/target/release/promptnotes /app/bin/promptnotes',
      // Install desktop entry
      `install -Dm644 packaging/linux/${FLATPAK_APP_ID}.desktop /app/share/applications/${FLATPAK_APP_ID}.desktop`,
      // Install icons
      `install -Dm644 packaging/linux/icons/128x128/apps/${FLATPAK_APP_ID}.png /app/share/icons/hicolor/128x128/apps/${FLATPAK_APP_ID}.png`,
      `install -Dm644 packaging/linux/icons/256x256/apps/${FLATPAK_APP_ID}.png /app/share/icons/hicolor/256x256/apps/${FLATPAK_APP_ID}.png`,
      // Install AppStream metainfo
      `install -Dm644 packaging/linux/${FLATPAK_APP_ID}.metainfo.xml /app/share/metainfo/${FLATPAK_APP_ID}.metainfo.xml`,
    ],
    sources: [
      {
        type: 'dir',
        path: '.',
      },
      // Cargo dependencies (generated by flatpak-cargo-generator)
      {
        type: 'file',
        path: 'packaging/flatpak/cargo-sources.json',
        dest: '.',
      },
      // npm dependencies (generated by flatpak-node-generator)
      {
        type: 'file',
        path: 'packaging/flatpak/npm-sources.json',
        dest: '.',
      },
    ],
  };
}

export function generateManifest(): FlatpakManifest {
  return {
    'app-id': FLATPAK_APP_ID,
    runtime: FLATPAK_RUNTIME,
    'runtime-version': FLATPAK_RUNTIME_VERSION,
    sdk: FLATPAK_SDK,
    'sdk-extensions': [...SDK_EXTENSIONS],
    command: 'promptnotes',
    'finish-args': [...FINISH_ARGS],
    'build-options': {
      'append-path': BUILD_PATH_APPEND,
      env: BUILD_ENV,
    },
    modules: [buildPromptNotesModule()],
  };
}

export function writeManifest(outputDir: string): void {
  const manifest = generateManifest();
  const outputPath = path.join(outputDir, `${FLATPAK_APP_ID}.json`);
  fs.mkdirSync(outputDir, { recursive: true });
  fs.writeFileSync(outputPath, JSON.stringify(manifest, null, 2) + '\n', 'utf-8');
  console.log(`Flatpak manifest written to: ${outputPath}`);
}

if (require.main === module) {
  const outputDir = process.argv[2] ?? path.resolve(__dirname, '../../../../packaging/flatpak');
  writeManifest(outputDir);
}
